/* ═══════════════════════════════════════════════════════════
   PROGRAM 2 — STRESS RECOVERY PATHWAY
   Lightweight module set — Phase headers, brief content
═══════════════════════════════════════════════════════════ */
var STRESS_RECOVERY_MODULES = [
  {
    id:'sr_m1',n:1,emoji:'🌊',courseId:'stress-recovery',courseName:'Stress Recovery Pathway',
    name:'Phase 1 — Acute Stress Relief',
    desc:'Immediate tools for reducing acute stress overload and returning to a regulated state.',
    lessons:[
      {id:'sr_m1_l1',name:'The Physiological Sigh',desc:'The fastest single technique for reducing acute stress',xp:60,tip:'Double inhale + long exhale. Do it now. Notice the shift.',
       content:`<h3>The Fastest Stress Reset Available</h3><p>The physiological sigh is a naturally occurring breath pattern your body uses to regulate CO2 levels and reduce acute stress. You can use it deliberately at any time.</p><h4>The Technique</h4><ol><li>Take a full inhale through the nose.</li><li>At the top of the inhale, take one more short sniff to fully inflate the lungs.</li><li>Release in one long, slow exhale through the mouth.</li></ol><p>Repeat 1–3 times. Stanford research shows this is the single fastest breath pattern for reducing physiological stress — faster than box breathing, faster than diaphragmatic breathing.</p><h4>When to Use It</h4><p>Before a difficult meeting. In a moment of overwhelm. When you notice tension building. When you wake anxious at 3am. This is your emergency reset — available any time, anywhere, in under 30 seconds.</p><div class="lesson-quiz"><h4>Knowledge Check</h4><p>What makes the physiological sigh uniquely effective for acute stress?</p><div class="quiz-options"><button class="qo" data-correct="false">It requires focused concentration which distracts from stress</button><button class="qo" data-correct="true">The double inhale fully inflates the lungs and the long exhale rapidly activates the parasympathetic system</button><button class="qo" data-correct="false">It is longer than other breath techniques so it gives more relaxation time</button></div></div>`},
      {id:'sr_m1_l2',name:'Cold Water Reset',desc:'Using cold water exposure to interrupt the stress response',xp:50,tip:'Splash cold water on your face — the dive reflex activates your vagus nerve immediately.',
       content:`<h3>The Dive Reflex</h3><p>Splashing cold water on your face activates the mammalian dive reflex — a hardwired physiological response that slows heart rate and activates the parasympathetic nervous system. It is one of the fastest, most accessible nervous system resets available.</p><h4>How to Use It</h4><ul><li>Splash cold water on your face, focusing on the forehead and around the eyes where the reflex receptors are most concentrated.</li><li>Hold a cold pack or ice in your hands for 30–60 seconds.</li><li>A brief cold shower (even 30 seconds at the end of a warm shower) significantly reduces cortisol.</li></ul><p>None of these require preparation. All of them work within seconds. Keep a cold pack in the freezer for your most overwhelming moments.</p><div class="lesson-quiz"><h4>Knowledge Check</h4><p>What physiological mechanism makes cold water effective for stress relief?</p><div class="quiz-options"><button class="qo" data-correct="false">Cold water distracts your nervous system from the stress</button><button class="qo" data-correct="true">It activates the mammalian dive reflex, which directly slows heart rate via the vagus nerve</button><button class="qo" data-correct="false">The discomfort of cold water makes stress feel comparatively minor</button></div></div>`},
      {id:'sr_m1_l3',name:'Grounding in 5 Minutes',desc:'The 5-4-3-2-1 technique for breaking the stress cycle',xp:60,tip:'Sensory grounding works even in the middle of a panic — it re-anchors you to now.',
       content:`<h3>When Stress Pulls You Into Your Head</h3><p>Much of the suffering in chronic stress comes not from the stressor itself but from the mental activity around it — rumination, catastrophising, and future-focused anxiety. Grounding interrupts this by forcibly returning attention to the present moment through sensory experience.</p><h4>5-4-3-2-1 Grounding</h4><ul><li><strong>5:</strong> Name 5 things you can see right now.</li><li><strong>4:</strong> Name 4 things you can physically feel (your feet on the floor, air on your skin).</li><li><strong>3:</strong> Name 3 things you can hear.</li><li><strong>2:</strong> Name 2 things you can smell (or would like to smell).</li><li><strong>1:</strong> Name 1 thing you can taste.</li></ul><p>Say each one slowly, out loud if possible. Notice what shifts as you move through the sequence. The stress response does not disappear, but your relationship to it changes — you are no longer inside it.</p><div class="lesson-quiz"><h4>Knowledge Check</h4><p>How does the 5-4-3-2-1 technique interrupt the stress response?</p><div class="quiz-options"><button class="qo" data-correct="false">It gives the mind a complex task that distracts it from stress</button><button class="qo" data-correct="true">It redirects attention from future-focused mental stress loops into present-moment sensory experience</button><button class="qo" data-correct="false">Counting down from 5 activates a relaxation reflex in the brain</button></div></div>`},
      {id:'sr_m1_l4',name:'The 90-Second Rule',desc:'Understanding how emotions move through the body and how to let them',xp:70,tip:'An emotion, allowed to move through the body fully, rarely lasts more than 90 seconds.',
       content:`<h3>Emotions as Physical Events</h3><p>Neuroscientist Dr Jill Bolte Taylor discovered that the biochemical signature of any single emotion — the physiological cascade of hormones and neural signals — lasts approximately 90 seconds in the body. What sustains emotional distress beyond 90 seconds is thinking — the story we tell about the emotion.</p><h4>The 90-Second Practice</h4><ol><li>When an emotion arises, name it simply: "anger," "fear," "grief," "shame."</li><li>Instead of trying to suppress, explain, or escape it, turn toward the physical sensation: where do you feel it in your body? What does it feel like — tight, heavy, sharp, hot?</li><li>Let it be there without adding a story. Breathe.</li><li>Notice: within 90 seconds to a few minutes, the sensation shifts or dissolves on its own.</li></ol><p>This does not make difficult emotions disappear permanently. But it stops them from becoming the chronic background noise that sustains the stress response.</p><div class="lesson-quiz"><h4>Knowledge Check</h4><p>According to Dr Jill Bolte Taylor, what sustains emotional distress beyond 90 seconds?</p><div class="quiz-options"><button class="qo" data-correct="false">The severity of the original trigger</button><button class="qo" data-correct="true">Thinking — the narrative and story we add to the emotion after the initial biochemical wave passes</button><button class="qo" data-correct="false">Emotional sensitivity and nervous system sensitivity</button></div></div>`}
    ]
  },
  {
    id:'sr_m2',n:2,emoji:'🌿',courseId:'stress-recovery',courseName:'Stress Recovery Pathway',
    name:'Phase 2 — Chronic Stress Management',
    desc:'Build sustainable systems for managing ongoing stress before it compounds into burnout.',
    lessons:[
      {id:'sr_m2_l1',name:'The Worry Window',desc:'Containing rumination so it does not colonise your entire day',xp:60,tip:'Scheduled worry time sounds counterintuitive — it works because it gives rumination a container.',
       content:`<h3>The Problem with Suppressing Worry</h3><p>Attempting to suppress anxious thoughts typically makes them more intrusive — a phenomenon called the rebound effect. Research by Daniel Wegner demonstrated that trying not to think about something increases the frequency with which you think about it.</p><h4>The Worry Window Technique</h4><ol><li>Designate a specific 20-minute window each day as your "worry time." Outside this window, when anxious thoughts arise, note them briefly and defer them: "I'll think about this at 5pm."</li><li>When the window arrives, actually worry — deliberately engage with the concerns you've deferred.</li><li>After 20 minutes, close the window. Any remaining worries are deferred to the next day's window.</li></ol><p>Over 2–3 weeks, most people find the volume of intrusive thoughts reduces significantly. The brain learns that concerns will be attended to — and reduces its urgency.</p><div class="lesson-quiz"><h4>Knowledge Check</h4><p>Why does scheduling worry time reduce intrusive thoughts?</p><div class="quiz-options"><button class="qo" data-correct="false">It makes worrying more efficient so less time is needed</button><button class="qo" data-correct="true">It gives the brain confirmation that concerns will be attended to, reducing urgency and intrusive repetition</button><button class="qo" data-correct="false">Worrying at a fixed time makes the thoughts less emotionally charged</button></div></div>`},
      {id:'sr_m2_l2',name:'Values Clarification',desc:'Understanding what genuinely matters to reduce misalignment stress',xp:70,tip:'Stress created by living against your values is the hardest kind — and the most solvable.',
       content:`<h3>Values Misalignment as Stress Source</h3><p>A significant but often invisible source of chronic stress is living in sustained misalignment with your own values — spending your time, energy, and attention on things that do not reflect what you most care about.</p><h4>Values Clarification Exercise</h4><ol><li>List 20 values (connection, creativity, security, freedom, contribution, health, etc.).</li><li>Narrow to your top 5 — the non-negotiables.</li><li>For each, rate: on a scale of 1–10, how much does my current life reflect this value?</li><li>Identify the largest gaps. These are the most significant sources of values-misalignment stress.</li></ol><h4>The Recovery Question</h4><p>You do not need to transform your life to reduce values stress. Even small, deliberate moves toward your core values — 15 minutes of creative work if creativity matters to you, a brief connection with someone important if relationships matter — can significantly shift the internal experience of a day.</p><div class="lesson-quiz"><h4>Knowledge Check</h4><p>What is values misalignment stress?</p><div class="quiz-options"><button class="qo" data-correct="false">Stress caused by not knowing what you value</button><button class="qo" data-correct="true">Chronic internal stress from living in sustained contradiction with your own core values</button><button class="qo" data-correct="false">Stress caused by having too many competing values</button></div></div>`},
      {id:'sr_m2_l3',name:'Stress Inoculation',desc:'Deliberately building stress tolerance through controlled micro-exposure',xp:80,tip:'Small, controlled doses of tolerable challenge build resilience — avoidance builds fragility.',
       content:`<h3>The Antifragility Principle</h3><p>Nassim Taleb's concept of antifragility describes systems that become stronger under manageable stress. Your nervous system is antifragile — but only when the stress dose is calibrated correctly. Too much for too long = burnout. Controlled, manageable challenge = resilience building.</p><h4>Stress Inoculation in Practice</h4><ul><li>Cold water exposure (brief — see earlier session)</li><li>Deliberately delaying a comfort behaviour for 5 minutes (checking phone, eating, etc.)</li><li>Having one slightly uncomfortable but important conversation per week</li><li>Doing something slightly unfamiliar once a week — a new route, a different cafe</li></ul><p>The key word is "controlled." These are not pushed-through challenges at the cost of your recovery. They are gentle expansions of your stress tolerance, within your current capacity window.</p><div class="lesson-quiz"><h4>Knowledge Check</h4><p>What distinguishes stress inoculation from simply pushing through stress?</p><div class="quiz-options"><button class="qo" data-correct="false">Stress inoculation must be done under medical supervision</button><button class="qo" data-correct="true">Stress inoculation involves controlled, calibrated doses within your capacity — not exceeding your current tolerance window</button><button class="qo" data-correct="false">Stress inoculation is only for people who have fully recovered from burnout</button></div></div>`},
      {id:'sr_m2_l4',name:'Recovery Week Design',desc:'Structuring one full week for maximum recovery — a practical framework',xp:80,tip:'You cannot recover in the same environment that caused the burnout. Change something deliberate.',
       content:`<h3>The Architecture of a Recovery Week</h3><p>A recovery week is not a holiday from life — it is a deliberately structured week in which recovery is the primary priority rather than an afterthought.</p><h4>The Five Elements</h4><ol><li><strong>Sleep protection:</strong> Non-negotiable consistent sleep and wake times, wind-down ritual, no alarms on at least one morning.</li><li><strong>Movement daily:</strong> Gentle, restorative — 20–30 minutes. Nature preferred.</li><li><strong>Connection:</strong> At least two genuine connections with safe people. Quality over quantity.</li><li><strong>Creative or joyful activity:</strong> At least one hour of something you genuinely enjoy or once enjoyed.</li><li><strong>Digital reduction:</strong> Deliberate, timed phone use. Significant reduction in news and social media.</li></ol><h4>The Honest Audit</h4><p>How many of these five elements does your current average week contain? This is not a judgement — it is a diagnostic. Each missing element is a recovery input your system is not receiving.</p><div class="lesson-quiz"><h4>Knowledge Check</h4><p>What is the primary purpose of a deliberately structured recovery week?</p><div class="quiz-options"><button class="qo" data-correct="false">To take a complete break from all responsibilities</button><button class="qo" data-correct="true">To make recovery the primary priority — ensuring all five key recovery inputs are present simultaneously</button><button class="qo" data-correct="false">To test whether you are recovered enough to return to full activity</button></div></div>`}
    ]
  }
];
STRESS_RECOVERY_MODULES.forEach(function(m){ window.FP_COURSE.modules.push(m); });

/* ═══════════════════════════════════════════════════════════
   PROGRAM 3 — FOCUS & CLARITY REBUILD
   Targeting cognitive burnout and brain fog
═══════════════════════════════════════════════════════════ */
var FOCUS_REBUILD_MODULES = [
  {
    id:'fr_m1',n:1,emoji:'🎯',courseId:'focus-rebuild',courseName:'Focus & Clarity Rebuild',
    name:'Phase 1 — Understanding Cognitive Burnout',
    desc:'Why your focus disappeared and what the recovery science says about getting it back.',
    lessons:[
      {id:'fr_m1_l1',name:'Brain Fog Explained',desc:'The neuroscience of cognitive burnout and what is actually happening',xp:60,tip:'Brain fog is not weakness — it is your prefrontal cortex operating under-resourced.',
       content:`<h3>What Brain Fog Actually Is</h3><p>Brain fog — difficulty concentrating, memory lapses, slow thinking, inability to make decisions — is one of the most debilitating symptoms of burnout. Understanding its neurological basis removes shame and clarifies the recovery path.</p><h4>The Neuroscience</h4><p>The prefrontal cortex (PFC) is responsible for executive functions: sustained attention, working memory, decision-making, impulse control, and emotional regulation. The PFC is extraordinarily sensitive to cortisol. Under chronic stress, elevated cortisol progressively reduces PFC function — literally impairing your capacity to think clearly.</p><p>Simultaneously, chronic stress over-activates the amygdala (the threat-detection centre), which competes for the neural resources the PFC needs. The net result is a brain that struggles with complex tasks, loses focus quickly, and feels overwhelmed by decisions that were previously simple.</p><h4>Recovery Timeline</h4><p>Cognitive function typically returns in stages: sleep quality improves first, then emotional regulation, then sustained attention, then complex decision-making. Full restoration often takes 3–9 months of consistent recovery practice. Understanding this prevents the demoralising experience of expecting function to return overnight.</p><div class="lesson-quiz"><h4>Knowledge Check</h4><p>Why does chronic stress impair focus and decision-making?</p><div class="quiz-options"><button class="qo" data-correct="false">Stress makes the brain work too fast to sustain concentration</button><button class="qo" data-correct="true">Elevated cortisol reduces prefrontal cortex function while over-activating the amygdala, competing for neural resources needed for clear thinking</button><button class="qo" data-correct="false">Brain fog is a sign of depression, not stress</button></div></div>`},
      {id:'fr_m1_l2',name:'Attention Restoration',desc:'Evidence-based practices for rebuilding depleted attention capacity',xp:70,tip:'Nature, not screens, is the fastest attention restorer available to you.',
       content:`<h3>Restoring What Burnout Depleted</h3><p>Attention is not just a psychological state — it is a physiological resource. Like muscle strength, it can be depleted through overuse and restored through specific practices. The key distinction is between directed attention (active, effortful, voluntary) and involuntary attention (effortless, fascinated, drawn).</p><h4>Directed Attention Fatigue (DAF)</h4><p>Burnout cognitive fatigue is primarily directed attention fatigue — the capacity for sustained voluntary focus is depleted. Passive screen time does not restore it. Active but effortless engagement does.</p><h4>Attention Restoration Practices</h4><ul><li><strong>Nature exposure:</strong> The single most researched attention restorer. Even 20 minutes in a natural environment measurably improves directed attention capacity.</li><li><strong>Open-focus meditation:</strong> Allowing attention to rest broadly rather than narrow-focusing.</li><li><strong>Creative play:</strong> Activities that engage involuntary attention — drawing, crafts, music — without task demands.</li><li><strong>Boredom (intentional):</strong> Deliberately doing nothing allows the default mode network to restore — the brain's rest-and-digest equivalent.</li></ul><div class="lesson-quiz"><h4>Knowledge Check</h4><p>Which activity best restores depleted directed attention?</p><div class="quiz-options"><button class="qo" data-correct="false">Watching a film for 2 hours</button><button class="qo" data-correct="true">20 minutes in a natural environment with no screen or goal</button><button class="qo" data-correct="false">A 90-minute nap</button></div></div>`},
      {id:'fr_m1_l3',name:'The Single-Tasking Protocol',desc:'How to rebuild focus capacity through structured single-tasking',xp:70,tip:'Multitasking is attention fragmentation. Single-tasking is attention training.',
       content:`<h3>Why Multitasking Destroys Focus Recovery</h3><p>Research by Dr Gloria Mark at UC Irvine found that after any interruption, it takes an average of 23 minutes to return to deep focused work. In a typical day of constant switching, the cumulative attention cost is enormous — and in burnout, the capacity to restore it after interruption is already compromised.</p><h4>The Single-Tasking Protocol</h4><ul><li><strong>One tab, one task.</strong> Close everything not relevant to the current task.</li><li><strong>Time block your focus.</strong> 20–25 minutes maximum for cognitively demanding tasks. Rest before the next block.</li><li><strong>Physically remove your phone</strong> from the workspace during focus blocks.</li><li><strong>Write your one task</strong> on a physical note before you begin. When distracted, return to it.</li></ul><h4>Building Capacity Gradually</h4><p>Start with 10-minute focus blocks if 20 feels too long. The goal is to finish a block without switching — not to maximise duration. Gradually increase as capacity returns. This is attention training, not productivity optimisation.</p><div class="lesson-quiz"><h4>Knowledge Check</h4><p>How long does research suggest it takes to return to deep focus after a typical interruption?</p><div class="quiz-options"><button class="qo" data-correct="false">3–5 minutes</button><button class="qo" data-correct="true">Approximately 23 minutes on average</button><button class="qo" data-correct="false">Only as long as the interruption itself took</button></div></div>`}
    ]
  }
];
FOCUS_REBUILD_MODULES.forEach(function(m){ window.FP_COURSE.modules.push(m); });

